import React from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { User, LogOut, ArrowLeft, LayoutDashboard } from 'lucide-react';

/* --- ESTILOS --- */
const headerContainer = {
  display: 'flex', justifyContent: 'space-between', alignItems: 'center',
  padding: '0 5%', background: '#1e293b', height: '75px',
  boxShadow: '0 2px 10px rgba(0,0,0,0.3)', position: 'sticky', top: 0, zIndex: 1000
};
const logoSection = { cursor: 'pointer', fontSize: '1.6rem', fontWeight: '800' };
const logoWhite = { color: '#ffffff' };
const logoOrange = { color: '#e67e22', marginLeft: '5px' };
const navLinks = { display: 'flex', alignItems: 'center', gap: '20px' };
const linkWhite = { color: '#ffffff', textDecoration: 'none', fontSize: '0.95rem', display: 'flex', alignItems: 'center', gap: '8px', fontWeight: '500' };
const loginButton = { background: '#e67e22', color: 'white', padding: '10px 25px', borderRadius: '12px', textDecoration: 'none', fontWeight: 'bold' };
const logoutBtn = { background: 'transparent', color: '#ff4d4d', border: '1px solid #ff4d4d', padding: '8px 15px', borderRadius: '12px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px' };

const Header = ({ isLoggedIn, userRole, cerrarSesion }) => {
  const navigate = useNavigate();
  const location = useLocation(); // Esto nos dice en qué página estamos

  return (
    <header style={headerContainer}>
      {/* LOGO */}
      <div style={logoSection} onClick={() => navigate('/')}>
        <span style={logoWhite}>OFERTAS</span>
        <span style={logoOrange}>APP</span>
      </div>

      <nav style={navLinks}>
        {/* CASO 1: USUARIO NO LOGUEADO */}
        {!isLoggedIn && (
          <>
            {/* Si NO estoy en Login, muestro Ingresar */}
            {location.pathname !== '/login' && (
              <>
                <Link to="/login" style={linkWhite}>
                  <User size={18} /> <span>Crear una cuenta</span>
                </Link>
                <Link to="/login" style={loginButton}>Ingresar</Link>
              </>
            )}
            {/* Si ESTOY en Login, muestro Volver y Crear Cuenta */}
            {location.pathname === '/login' && (
              <>
                <button onClick={() => navigate('/')} style={{...linkWhite, background:'none', border:'none', cursor:'pointer'}}>
                  <ArrowLeft size={18} /> Volver
                </button>
                <Link to="/login" style={linkWhite}>Crear una cuenta</Link>
              </>
            )}
          </>
        )}

        {/* CASO 2: USUARIO LOGUEADO */}
        {isLoggedIn && (
          <>
            {/* Si es Vendedor y NO está en el dashboard, mostrar botón al panel */}
            {userRole === 'vendedor' && location.pathname !== '/dashboard' && (
              <Link to="/dashboard" style={linkWhite}>
                <LayoutDashboard size={18} /> <span>Panel de Control</span>
              </Link>
            )}
            
            {/* Botón de Salir siempre visible si está logueado */}
            <button onClick={cerrarSesion} style={logoutBtn}>
              <LogOut size={18} />
              <span>Cerrar Sesión</span>
            </button>
          </>
        )}
      </nav>
    </header>
  );
};

export default Header;
